// Mock client registration
clients.set('client1', { 
  id: 'client1', 
  secret: 'clientsecret123', 
  redirectUris: ['http://localhost:3000/callback'] 
});

// Middleware to parse URL-encoded bodies
app.use(express.urlencoded({ extended: true }));

// Authorization endpoint
app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state } = req.query;
  
  // Validate client
  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }
  
  // Validate redirect_uri
  if (!client.redirectUris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'invalid_request' });
  }
  
  // Validate response_type
  if (response_type !== 'code') {
    return res.status(400).json({ error: 'unsupported_response_type' });
  }
  
  // Check if user is logged in (simplified)
  const isLoggedIn = req.session && req.session.userId;
  
  if (!isLoggedIn) {
    // Redirect to login page
    return res.redirect(`/login?redirect_uri=${encodeURIComponent(redirect_uri)}&client_id=${client_id}&state=${state}`);
  }
  
  // Generate authorization code
  const code = crypto.randomBytes(32).toString('hex');
  const authCode = {
    code,
    client_id,
    redirect_uri,
    scope,
    user_id: req.session.userId,
    expires_at: Date.now() + 300000 // 5 minutes
  };
  
  authCodes.set(code, authCode);
  
  // Redirect with authorization code
  const redirectUrl = `${redirect_uri}?code=${code}`;
  if (state) {
    redirectUrl += `&state=${state}`;
  }
  
  res.redirect(redirectUrl);
});

