// Handle login
app.post('/login', (req, res) => {
  const { username, password, redirect_uri, client_id, state } = req.body;
  
  const user = users.get(username);
  if (user && user.password === password) {
    // Store user session
    req.session = { userId: user.id };
    
    // Redirect to authorization endpoint
    const redirectUrl = `/authorize?response_type=code&client_id=${client_id}&redirect_uri=${encodeURIComponent(redirect_uri)}&state=${state}`;
    res.redirect(redirectUrl);
  } else {
    res.status(401).send('Invalid credentials');
  }
});

// Token endpoint
app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;
  
  // Validate client
  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }
  
  // Validate client secret
  if (client.secret !== client_secret) {
    return res.status(400).json({ error: 'invalid_client' });
  }
  
  // Validate grant type
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }
  
  // Validate authorization code
  const authCode = authCodes.get(code);
  if (!authCode) {
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  // Check if code has expired
  if (authCode.expires_at < Date.now()) {
    authCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  // Check if redirect_uri matches
  if (authCode.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  // Generate access token
  const accessToken = crypto.randomBytes(32).toString('hex');
  const tokenData = {
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    scope: authCode.scope,
    user_id: authCode.user_id
  };
  
  accessTokens.set(accessToken, tokenData);
  
  // Remove used authorization code
  authCodes.delete(code);
  
  res.json(tokenData);
});

